def HSS(points, k: int, reference_point) -> np.ndarray:
    n, m = points.shape

    if k <= 0 or k > n:
        raise ValueError("k must be greater than 0 and not larger than the number of points.")

    # 创建索引列表
    R_indices = list(range(n))
    R_objectives_array = points
    random.shuffle(R_indices)

    # 1. GSI算法 - 初始化
    S = set(R_indices[:k])
    elements_to_insert = R_indices[k:]

    # 2. GSI算法 - 迭代过程
    for element_to_add in elements_to_insert:
        S.add(element_to_add)

        worst_element_index = None
        min_contribution = float('inf')

        # 获取当前 S 的超体积
        if not S:
            M = R_objectives_array.shape[1] if R_objectives_array.ndim == 2 else 0
            current_selected = np.empty((0, M))
        else:
            current_selected = R_objectives_array[list(S)]

        if current_selected.size == 0:
            current_hv = 0.0
        else:
            try:
                hv = pg.hypervolume(current_selected)
                current_hv = hv.compute(reference_point)
            except Exception as e:
                print(f"Hypervolume calculation error: {e}")
                current_hv = 0.0

        for s_index in list(S):
            # 尝试移除 s_index: S_temp = S - {s_index}
            S_temp = S - {s_index}

            # 移除后的超体积
            if not S_temp:
                M = R_objectives_array.shape[1] if R_objectives_array.ndim == 2 else 0
                temp_selected = np.empty((0, M))
            else:
                temp_selected = R_objectives_array[list(S_temp)]

            if temp_selected.size == 0:
                hv_after_remove = 0.0
            else:
                try:
                    hv = pg.hypervolume(temp_selected)
                    hv_after_remove = hv.compute(reference_point)
                except Exception as e:
                    print(f"Hypervolume calculation error: {e}")
                    hv_after_remove = 0.0

            # 贡献度 = 移除前的 HV - 移除后的 HV
            contribution = current_hv - hv_after_remove

            if contribution < min_contribution:
                min_contribution = contribution
                worst_element_index = s_index

        if worst_element_index is not None:
            S.remove(worst_element_index)

    # 3. LS算法 - 初始化
    current_S = set(S)
    R_set = set(R_indices)

    if len(current_S) != k:
        raise ValueError("初始子集 S 的大小必须等于 k。")

    # 4. LS算法 - 迭代过程
    while True:
        # 获取当前 S 的超体积
        if not current_S:
            M = R_objectives_array.shape[1] if R_objectives_array.ndim == 2 else 0
            current_selected = np.empty((0, M))
        else:
            current_selected = R_objectives_array[list(current_S)]

        if current_selected.size == 0:
            current_hv = 0.0
        else:
            try:
                hv = pg.hypervolume(current_selected)
                current_hv = hv.compute(reference_point)
            except Exception as e:
                print(f"Hypervolume calculation error: {e}")
                current_hv = 0.0

        found_improvement = False

        R_minus_S = list(R_set - current_S)
        S_list = list(current_S)

        # 遍历所有可能的交换对 (s, r)
        for s_index in S_list:
            for r_index in R_minus_S:
                # 尝试交换: S' = S - {s_index} + {r_index}
                S_new = (current_S - {s_index}) | {r_index}

                # 计算新集合 S_new 的超体积
                if not S_new:
                    M = R_objectives_array.shape[1] if R_objectives_array.ndim == 2 else 0
                    new_selected = np.empty((0, M))
                else:
                    new_selected = R_objectives_array[list(S_new)]

                if new_selected.size == 0:
                    new_hv = 0.0
                else:
                    try:
                        hv = pg.hypervolume(new_selected)
                        new_hv = hv.compute(reference_point)
                    except Exception as e:
                        print(f"Hypervolume calculation error: {e}")
                        new_hv = 0.0

                # 检查是否是改进
                if new_hv > current_hv:
                    current_S = S_new
                    found_improvement = True
                    break  # 跳出 r_index 循环

            if found_improvement:
                break  # 跳出 s_index 循环

        if not found_improvement:
            break

    # 5. 返回选择的点
    if not current_S:
        M = R_objectives_array.shape[1] if R_objectives_array.ndim == 2 else 0
        selected_points = np.empty((0, M))
    else:
        selected_points = R_objectives_array[list(current_S)]

    return selected_points

def HSS(points, k: int, reference_point) -> np.ndarray:
    n, m = points.shape

    if reference_point is None:
        reference_point = np.max(points, axis=0) * 1.1

    # 初始化候选池（大小为 2k）
    candidate_pool_size = min(2 * k, n)
    indices = list(range(n))
    random.shuffle(indices)
    candidate_pool = set(indices[:candidate_pool_size])

    # 缓存超体积贡献
    contribution_cache = {}

    def compute_hv_contribution(subset_indices, element_idx):
        """计算元素对子集的超体积贡献（带缓存）"""
        cache_key = (frozenset(subset_indices), element_idx)
        if cache_key in contribution_cache:
            return contribution_cache[cache_key]

        if not subset_indices:
            subset_points = np.empty((0, m))
        else:
            subset_points = points[list(subset_indices)]

        # 计算包含元素的超体积
        if not (subset_indices | {element_idx}):
            combined_points = np.empty((0, m))
        else:
            combined_points = points[list(subset_indices | {element_idx})]

        if subset_points.size == 0:
            hv_subset = 0.0
        else:
            try:
                hv = pg.hypervolume(subset_points)
                hv_subset = hv.compute(reference_point)
            except:
                hv_subset = 0.0

        if combined_points.size == 0:
            hv_combined = 0.0
        else:
            try:
                hv = pg.hypervolume(combined_points)
                hv_combined = hv.compute(reference_point)
            except:
                hv_combined = 0.0

        contribution = hv_combined - hv_subset
        contribution_cache[cache_key] = contribution
        return contribution

    # 初始贪心选择
    current_subset = set()
    remaining_candidates = candidate_pool.copy()

    for _ in range(k):
        if not remaining_candidates:
            break

        best_candidate = None
        best_contribution = -float('inf')

        for candidate in remaining_candidates:
            contribution = compute_hv_contribution(current_subset, candidate)
            if contribution > best_contribution:
                best_contribution = contribution
                best_candidate = candidate

        if best_candidate is not None:
            current_subset.add(best_candidate)
            remaining_candidates.remove(best_candidate)

    # 迭代精炼
    max_iterations = 100
    for iteration in range(max_iterations):
        improved = False

        # 计算当前超体积
        if not current_subset:
            current_points = np.empty((0, m))
        else:
            current_points = points[list(current_subset)]

        if current_points.size == 0:
            current_hv = 0.0
        else:
            try:
                hv = pg.hypervolume(current_points)
                current_hv = hv.compute(reference_point)
            except:
                current_hv = 0.0

        # 尝试替换操作
        for s in list(current_subset):
            for r in candidate_pool - current_subset:
                # 创建新子集
                new_subset = (current_subset - {s}) | {r}

                # 计算新超体积
                if not new_subset:
                    new_points = np.empty((0, m))
                else:
                    new_points = points[list(new_subset)]

                if new_points.size == 0:
                    new_hv = 0.0
                else:
                    try:
                        hv = pg.hypervolume(new_points)
                        new_hv = hv.compute(reference_point)
                    except:
                        new_hv = 0.0

                # 如果改进则接受
                if new_hv > current_hv:
                    current_subset = new_subset
                    improved = True
                    break

            if improved:
                break

        # 如果没有改进，尝试多样性增强的突变
        if not improved and iteration % 5 == 0:
            # 计算点之间的最小距离
            if len(current_subset) > 1:
                subset_points = points[list(current_subset)]
                distances = cdist(subset_points, subset_points)
                np.fill_diagonal(distances, np.inf)
                min_dist = np.min(distances)

                # 寻找可以增加多样性的替换
                for s in list(current_subset):
                    for r in candidate_pool - current_subset:
                        # 检查是否增加多样性
                        temp_subset = (current_subset - {s}) | {r}
                        temp_points = points[list(temp_subset)]

                        if len(temp_subset) > 1:
                            temp_distances = cdist(temp_points, temp_points)
                            np.fill_diagonal(temp_distances, np.inf)
                            temp_min_dist = np.min(temp_distances)

                            if temp_min_dist > min_dist * 1.1:  # 多样性增加10%以上
                                current_subset = temp_subset
                                improved = True
                                break

                    if improved:
                        break

        # 如果没有改进，退出循环
        if not improved:
            break

    # 返回选择的点
    if not current_subset:
        return np.empty((0, m))

    selected_indices = sorted(list(current_subset))
    return points[selected_indices]
